import React, { useState, useRef } from 'react';
import { Mail, Lock, User, Ruler, Palette, ChevronRight, ChevronLeft, Sparkles, Shirt, Camera, Users } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import './AuthPage.css';

const AuthPage = () => {
  const navigate = useNavigate();
  const [isLogin, setIsLogin] = useState(true);
  const [step, setStep] = useState(1);
  const [message, setMessage] = useState({ text: '', type: '' });
  const fileInputRef = useRef(null);
  
  // Added a separate state for the image preview (the blob) 
  // while keeping the actual file in formData.profileImage
  const [imagePreview, setImagePreview] = useState(null);

  const [formData, setFormData] = useState({
    name: '', email: '', password: '', gender: '',
    height: '', weight: '', skinTone: '',
    chest: '', profileImage: null // This will now store the actual FILE object
  });

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setFormData({ ...formData, profileImage: file }); // Store the actual file
      setImagePreview(URL.createObjectURL(file)); // Store the preview URL
    }
  };
               
  const handleSubmit = async (e) => {
    e.preventDefault();
    const endpoint = isLogin ? '/api/auth/login' : '/api/auth/register';
    
    try {
      let response;
      
      if (isLogin) {
        // LOGIN: Keep using JSON as before
        response = await fetch(`http://localhost:5000${endpoint}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email: formData.email, password: formData.password })
        });
      } else {
        // REGISTER: Use FormData to send the actual file
        const data = new FormData();
        // Append all text fields
        Object.keys(formData).forEach(key => {
          if (key !== 'profileImage') {
            data.append(key, formData[key]);
          }
        });
        // Append the actual file
        if (formData.profileImage) {
          data.append('profileImage', formData.profileImage);
        }

        response = await fetch(`http://localhost:5000${endpoint}`, {
          method: 'POST',
          // Note: DO NOT set Content-Type header here; 
          // Browser sets it automatically for FormData
          body: data 
        });
      }

      const data = await response.json();

      if (response.ok) {
        setMessage({ text: data.message, type: 'success' });

        if (isLogin) {
          localStorage.setItem('token', data.token);
          localStorage.setItem('user', JSON.stringify(data.user)); 
          setTimeout(() => navigate('/dashboard'), 1500);
        } else {
          setTimeout(() => {
            setIsLogin(true);
            setStep(1);
            setImagePreview(null);
            setMessage({ text: 'Registration successful! Please sign in.', type: 'success' });
          }, 1500);
        }
      } else {
        setMessage({ text: data.message || "Authentication Failed", type: 'error' });
      }
    } catch (err) {
      setMessage({ text: "Connection Failed", type: 'error' });
    }
  };

  const nextStep = () => setStep(step + 1);
  const prevStep = () => setStep(step - 1);

  return (
    <div className="auth-fluid-wrapper">
      <div className="auth-ambient-glow"></div>
      <div className="auth-split-layout">
        <div className="auth-brand-side">
          <div className="brand-sticky-content">
            <div className="auth-logo-premium">
              <span className="sparkle-icon"><Sparkles size={32} /></span>
              <span>StyleMirror</span>
            </div>
            <h1 className="brand-statement">
              {isLogin ? "Welcome back to the " : "Define your "}
              <span className="text-gradient">Digital Silhouette.</span>
            </h1>
          </div>
        </div>

        <div className="auth-form-side">
          <div className="form-inner-container">
            <header className="form-nav">
              <button className={isLogin ? "nav-active" : ""} onClick={() => setIsLogin(true)}>Sign In</button>
              <button className={!isLogin ? "nav-active" : ""} onClick={() => setIsLogin(false)}>Register</button>
            </header>

            {message.text && <div className={`auth-alert ${message.type}`}>{message.text}</div>}

            <form className="fluid-form" onSubmit={handleSubmit}>
              {isLogin ? (
                <div className="form-step-animate">
                  <div className="input-field">
                    <label>Email Address</label>
                    <div className="input-box"><Mail size={18} /><input type="email" name="email" onChange={handleInputChange} required /></div>
                  </div>
                  <div className="input-field">
                    <label>Password</label>
                    <div className="input-box"><Lock size={18} /><input type="password" name="password" onChange={handleInputChange} required /></div>
                  </div>
                </div>
              ) : (
                <div className="form-step-animate">
                  {step === 1 ? (
                    <div className="step-content">
                      <div className="profile-upload-section">
                        <div className="image-preview-circle" onClick={() => fileInputRef.current.click()}>
                          {imagePreview ? <img src={imagePreview} alt="Preview" /> : <Camera size={24} />}
                        </div>
                        <input type="file" hidden ref={fileInputRef} onChange={handleImageChange} accept="image/*" />
                        <span className="upload-label">Upload Profile Photo</span>
                      </div>
                      <div className="input-field">
                        <label>Full Name</label>
                        <div className="input-box"><User size={18} /><input type="text" name="name" onChange={handleInputChange} /></div>
                      </div>
                      <div className="input-field">
                        <label>Email</label>
                        <div className="input-box"><Mail size={18} /><input type="email" name="email" onChange={handleInputChange} required /></div>
                      </div>
                      <div className="input-field">
                        <label>Password</label>
                        <div className="input-box"><Lock size={18} /><input type="password" name="password" onChange={handleInputChange} required /></div>
                      </div>
                    </div>
                  ) : (
                    <div className="step-content grid-inputs">
                      <div className="input-field"><label>Height (cm)</label><div className="input-box"><Ruler size={18} /><input type="number" name="height" onChange={handleInputChange} /></div></div>
                      <div className="input-field"><label>Weight (kg)</label><div className="input-box"><User size={18} /><input type="number" name="weight" onChange={handleInputChange} /></div></div>
                      <div className="input-field"><label>Skin Tone</label><div className="input-box"><Palette size={18} /><input type="text" name="skinTone" onChange={handleInputChange} /></div></div>
                      <div className="input-field"><label>Chest (cm)</label><div className="input-box"><Shirt size={18} /><input type="number" name="chest" onChange={handleInputChange} /></div></div>
                    </div>
                  )}
                </div>
              )}

              <div className="form-footer-actions">
                {!isLogin && step === 1 ? (
                  <button type="button" className="btn-fluid-primary" onClick={nextStep}>Next Step <ChevronRight size={18} /></button>
                ) : (
                  <div className="btn-combo">
                    {!isLogin && <button type="button" className="btn-fluid-outline" onClick={prevStep}><ChevronLeft size={20} /></button>}
                    <button type="submit" className="btn-fluid-primary">{isLogin ? "Authenticate" : "Finalize Profile"}</button>
                  </div>
                )}
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
